package main

import (
	"fmt"
	"os"
	"os/exec"
)

// QuerySLBAndExport queries SLB information and exports it to a file
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Connect the pipeline: aliyun output -> jq input
	pipe, err := aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	jqCmd.Stdin = pipe
	jqCmd.Stdout = outFile

	// Capture stderr for both commands
	aliyunStderr, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create aliyun stderr pipe: %w", err)
	}

	jqStderr, err := jqCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stderr pipe: %w", err)
	}

	// Start jq command first (it needs to be ready to receive input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Read stderr from aliyun
	aliyunStderrBytes := make([]byte, 0)
	go func() {
		buf := make([]byte, 1024)
		for {
			n, err := aliyunStderr.Read(buf)
			if n > 0 {
				aliyunStderrBytes = append(aliyunStderrBytes, buf[:n]...)
			}
			if err != nil {
				break
			}
		}
	}()

	// Read stderr from jq
	jqStderrBytes := make([]byte, 0)
	go func() {
		buf := make([]byte, 1024)
		for {
			n, err := jqStderr.Read(buf)
			if n > 0 {
				jqStderrBytes = append(jqStderrBytes, buf[:n]...)
			}
			if err != nil {
				break
			}
		}
	}()

	// Wait for aliyun command to complete
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, string(aliyunStderrBytes))
	}

	// Close the pipe to signal jq that input is complete
	pipe.Close()

	// Wait for jq command to complete
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, string(jqStderrBytes))
	}

	return fmt.Sprintf("Successfully exported SLB information to %s", outputFile), nil
}

func main() {
	// Example usage
	loadBalancerName := "my-slb"
	outputFile := "output.json"

	// Allow command line arguments to override defaults
	if len(os.Args) > 1 {
		loadBalancerName = os.Args[1]
	}
	if len(os.Args) > 2 {
		outputFile = os.Args[2]
	}

	result, err := QuerySLBAndExport(loadBalancerName, outputFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Println(result)
}

