// isValidLoadBalancerName validates the load balancer name
// Allows alphanumeric characters, hyphens, underscores, and dots
func isValidLoadBalancerName(name string) bool {
	if name == "" || len(name) > 255 {
		return false
	}
	// Only allow safe characters
	validPattern := regexp.MustCompile(`^[a-zA-Z0-9._-]+$`)
	return validPattern.MatchString(name)
}

// sanitizeFilePath validates and sanitizes the file path
func sanitizeFilePath(path string) (string, error) {
	if path == "" {
		return "", fmt.Errorf("path cannot be empty")
	}

	// Clean the path to resolve any .. or . components
	cleanPath := filepath.Clean(path)

	// Prevent absolute paths or paths that escape the current directory
	if filepath.IsAbs(cleanPath) {
		return "", fmt.Errorf("absolute paths are not allowed")
	}

	// Check for directory traversal attempts
	if len(cleanPath) >= 2 && cleanPath[:2] == ".." {
		return "", fmt.Errorf("directory traversal is not allowed")
	}

	// Validate filename characters (alphanumeric, dash, underscore, dot, forward slash for subdirs)
	validPattern := regexp.MustCompile(`^[a-zA-Z0-9._/-]+$`)
	if !validPattern.MatchString(cleanPath) {
		return "", fmt.Errorf("path contains invalid characters")
	}

	// Ensure the file has a .json extension for safety
	if filepath.Ext(cleanPath) != ".json" {
		return "", fmt.Errorf("output file must have .json extension")
	}

	return cleanPath, nil
}

