}

// validateInputs performs input validation to prevent injection attacks
func validateInputs(loadBalancerName string, outputFile string) error {
	// Validate loadBalancerName
	if loadBalancerName == "" {
		return fmt.Errorf("loadBalancerName cannot be empty")
	}

