	// Execute jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create output file
	outFile, err := os.Create(cleanPath)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Set up the pipeline: aliyun | jq > file
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	jqCmd.Stdout = outFile

	// Capture stderr for both commands
	aliyunStderr, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stderr pipe for aliyun: %w", err)
	}

	jqStderr, err := jqCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stderr pipe for jq: %w", err)
	}

	// Start jq first (it will wait for input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		jqCmd.Process.Kill()
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun to complete
	aliyunErr := aliyunCmd.Wait()

	// Wait for jq to complete
	jqErr := jqCmd.Wait()

	// Read any error output
	aliyunErrBytes := make([]byte, 4096)
	jqErrBytes := make([]byte, 4096)
	aliyunStderr.Read(aliyunErrBytes)
	jqStderr.Read(jqErrBytes)

	if aliyunErr != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", aliyunErr, string(aliyunErrBytes))
	}

	if jqErr != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", jqErr, string(jqErrBytes))
	}

	return fmt.Sprintf("Successfully exported SLB information to %s", cleanPath), nil
}

// isValidLoadBalancerName validates the load balancer name
// Allow alphanumeric characters, hyphens, underscores, dots, and Chinese characters
func isValidLoadBalancerName(name string) bool {
	if name == "" || len(name) > 256 {
		return false
	}

	// Allow alphanumeric, hyphens, underscores, dots, and spaces
	// This is a reasonable pattern for load balancer names
	matched, _ := regexp.MatchString(`^[a-zA-Z0-9._\-\p{Han} ]+$`, name)
	return matched
}

// validateOutputFile validates and sanitizes the output file path
func validateOutputFile(path string) (string, error) {
	if path == "" {
		return "", fmt.Errorf("output file path cannot be empty")
	}

	// Clean the path to prevent directory traversal
	cleanPath := filepath.Clean(path)

	// Ensure the path doesn't try to escape using ../
	absPath, err := filepath.Abs(cleanPath)
	if err != nil {
		return "", fmt.Errorf("failed to resolve absolute path: %w", err)
	}

	// Get current working directory
	cwd, err := os.Getwd()
	if err != nil {
		return "", fmt.Errorf("failed to get current directory: %w", err)
	}

	// Ensure the file is within the current working directory or its subdirectories
	relPath, err := filepath.Rel(cwd, absPath)
	if err != nil {
		return "", fmt.Errorf("failed to get relative path: %w", err)
	}

	// Check if the path tries to go outside the current directory
	if len(relPath) > 0 && relPath[0:2] == ".." {
		return "", fmt.Errorf("output file must be within the current directory")
	}

	// Validate file extension (optional but recommended)
	ext := filepath.Ext(cleanPath)
	if ext != ".json" {
		return "", fmt.Errorf("output file must have .json extension")
	}

	return absPath, nil
}

