// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate loadBalancerName - allow only alphanumeric, hyphens, underscores, and dots
	// This prevents command injection through the name parameter
	if !isValidLoadBalancerName(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName: contains invalid characters")
	}

	// Validate and sanitize output file path
	cleanOutputFile, err := validateOutputFile(outputFile)
	if err != nil {
		return "", fmt.Errorf("invalid outputFile: %w", err)
	}

	// Execute aliyun command with proper argument passing (no shell)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Execute jq command with proper argument passing (no shell)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create output file
	outFile, err := os.Create(cleanOutputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Set up the pipeline
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	jqCmd.Stdout = outFile

	// Capture stderr for both commands
	aliyunStderr, err := aliyunCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stderr pipe for aliyun: %w", err)
	}

	jqStderr, err := jqCmd.StderrPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create stderr pipe for jq: %w", err)
	}

	// Start jq first (it will wait for input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		jqCmd.Process.Kill()
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Wait for aliyun to complete
	aliyunErr := aliyunCmd.Wait()

	// Wait for jq to complete
	jqErr := jqCmd.Wait()

	// Read stderr outputs
	aliyunStderrBytes := make([]byte, 4096)
	aliyunStderrLen, _ := aliyunStderr.Read(aliyunStderrBytes)

	jqStderrBytes := make([]byte, 4096)
	jqStderrLen, _ := jqStderr.Read(jqStderrBytes)

	// Check for errors
	if aliyunErr != nil {
		return string(aliyunStderrBytes[:aliyunStderrLen]), fmt.Errorf("aliyun command failed: %w", aliyunErr)
	}

	if jqErr != nil {
		return string(jqStderrBytes[:jqStderrLen]), fmt.Errorf("jq command failed: %w", jqErr)
	}

	return fmt.Sprintf("Successfully exported SLB information to %s", cleanOutputFile), nil
}

// isValidLoadBalancerName validates the load balancer name
// Only allows alphanumeric characters, hyphens, underscores, dots, and Chinese characters
func isValidLoadBalancerName(name string) bool {
	if name == "" || len(name) > 256 {
		return false
	}

	// Allow alphanumeric, hyphens, underscores, dots, and common characters
	// Reject any shell metacharacters
	matched, _ := regexp.MatchString(`^[a-zA-Z0-9._-]+$`, name)
	return matched
}

// validateOutputFile validates and cleans the output file path
func validateOutputFile(path string) (string, error) {
	if path == "" {
		return "", fmt.Errorf("output file path cannot be empty")
	}

	// Clean the path to prevent directory traversal
	cleanPath := filepath.Clean(path)

	// Ensure the path doesn't contain shell metacharacters
	matched, _ := regexp.MatchString(`^[a-zA-Z0-9._/-]+$`, cleanPath)
	if !matched {
		return "", fmt.Errorf("path contains invalid characters")
	}

	// Prevent absolute paths or paths that traverse outside current directory
	if filepath.IsAbs(cleanPath) {
		return "", fmt.Errorf("absolute paths are not allowed")
	}

	// Check for directory traversal attempts
	if matched, _ := regexp.MatchString(`\.\.`, cleanPath); matched {
		return "", fmt.Errorf("directory traversal is not allowed")
	}

	return cleanPath, nil
}

