func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a buffer to capture the output from aliyun command
	var aliyunOut bytes.Buffer
	var aliyunErr bytes.Buffer
	aliyunCmd.Stdout = &aliyunOut
	aliyunCmd.Stderr = &aliyunErr

	// Execute aliyun command
	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to execute aliyun command: %v, stderr: %s", err, aliyunErr.String())
	}

	// Set the output of aliyun as input to jq
	jqCmd.Stdin = &aliyunOut

	// Create buffers for jq output
	var jqOut bytes.Buffer
	var jqErr bytes.Buffer
	jqCmd.Stdout = &jqOut
	jqCmd.Stderr = &jqErr

	// Execute jq command
	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to execute jq command: %v, stderr: %s", err, jqErr.String())
	}

	// Write the output to file
	if err := os.WriteFile(outputFile, jqOut.Bytes(), 0644); err != nil {
		return "", fmt.Errorf("failed to write output to file: %v", err)
	}

	result := fmt.Sprintf("Successfully exported SLB information to %s", outputFile)
	return result, nil
}

