	// Set the output from aliyun as input to jq
	jqCmd.Stdin = &aliyunOutput

	// Create buffers for jq output
	var jqOutput bytes.Buffer
	var jqError bytes.Buffer
	jqCmd.Stdout = &jqOutput
	jqCmd.Stderr = &jqError

	// Execute jq command
	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to execute jq command: %v, stderr: %s", err, jqError.String())
	}

	// Write the result to the output file
	if err := os.WriteFile(outputFile, jqOutput.Bytes(), 0644); err != nil {
