package main

import (
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Enhanced input validation
	if err := validateInput(loadBalancerName); err != nil {
		return "", fmt.Errorf("invalid loadBalancerName: %w", err)
	}
	if err := validateInput(outputFile); err != nil {
		return "", fmt.Errorf("invalid outputFile: %w", err)
	}

	// Create the output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// First command: aliyun slb DescribeLoadBalancers
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Second command: jq
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Connect the pipeline: aliyun output -> jq input
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	// Capture jq's output to write to file
	jqCmd.Stdout = outFile

	// Capture stderr from both commands for error reporting
	var aliyunStderr, jqStderr strings.Builder
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Start jq first (it will wait for input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Run(); err != nil {
		jqCmd.Wait() // Clean up jq process
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for jq to finish processing
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	// Read the output file to return its content
	outFile.Seek(0, 0)
	outputBytes, err := io.ReadAll(outFile)
	if err != nil {
		return "", fmt.Errorf("failed to read output file: %w", err)
	}

	return string(outputBytes), nil
}

// validateInput checks for potentially dangerous characters
func validateInput(input string) error {
	if input == "" {
		return fmt.Errorf("input cannot be empty")
	}

	// Check for shell metacharacters and control characters
	dangerousChars := "`$\n\r\t|><;&(){}[]'\"\\*?!"
	if strings.ContainsAny(input, dangerousChars) {
		return fmt.Errorf("input contains invalid characters")
	}

	return nil
}

