// isValidLoadBalancerName checks if the load balancer name contains only safe characters
func isValidLoadBalancerName(name string) bool {
	if name == "" {
		return false
	}
	// Allow alphanumeric, hyphens, underscores, dots, and Chinese characters (common in Aliyun)
	// Limit length to prevent abuse
	if len(name) > 256 {
		return false
	}
	matched, _ := regexp.MatchString(`^[\w\-\.]+$`, name)
	return matched
}

// validateAndCleanPath validates and cleans the file path to prevent path traversal
func validateAndCleanPath(path string) (string, error) {
	if path == "" {
		return "", fmt.Errorf("path cannot be empty")
	}

	// Clean the path to resolve any .. or . components
	cleanPath := filepath.Clean(path)

	// Check for path traversal attempts
	if filepath.IsAbs(cleanPath) {
		// If absolute path, ensure it doesn't try to escape to sensitive directories
		// For production, you might want to restrict to specific directories
		absPath, err := filepath.Abs(cleanPath)
		if err != nil {
			return "", fmt.Errorf("invalid absolute path: %w", err)
		}
		cleanPath = absPath
	} else {
		// For relative paths, convert to absolute and verify
		absPath, err := filepath.Abs(cleanPath)
		if err != nil {
			return "", fmt.Errorf("invalid path: %w", err)
		}
		cleanPath = absPath
	}

	// Ensure the file has .json extension for safety
	if filepath.Ext(cleanPath) != ".json" {
		return "", fmt.Errorf("output file must have .json extension")
	}

	// Check if the directory exists or can be created
	dir := filepath.Dir(cleanPath)
	if err := os.MkdirAll(dir, 0755); err != nil {
		return "", fmt.Errorf("cannot create directory: %w", err)
	}

	return cleanPath, nil
}

