package main

import (
	"fmt"
	"io"
	"os"
	"os/exec"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate input parameters
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Additional validation to prevent path traversal and other issues
	if strings.Contains(outputFile, "..") {
		return "", fmt.Errorf("invalid outputFile path")
	}

	// Create the first command: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the second command: jq '.LoadBalancers.LoadBalancer[]'
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create output file
	outFile, err := os.Create(outputFile)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Set up the pipeline
	// Connect aliyun stdout to jq stdin
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	// Capture jq output for both file and return value
	jqStdout, err := jqCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create jq stdout pipe: %w", err)
	}

	// Capture stderr from both commands
	aliyunCmd.Stderr = os.Stderr
	jqCmd.Stderr = os.Stderr

	// Start jq command first (it will wait for input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start aliyun command: %w", err)
	}

	// Read jq output and write to both file and string buffer
	var outputBuilder strings.Builder
	multiWriter := io.MultiWriter(outFile, &outputBuilder)

	if _, err := io.Copy(multiWriter, jqStdout); err != nil {
		return "", fmt.Errorf("failed to copy output: %w", err)
	}

	// Wait for both commands to complete
	if err := aliyunCmd.Wait(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	return outputBuilder.String(), nil
}

func main() {
	// Example usage
	result, err := QuerySLBAndExport("my-load-balancer", "output.json")
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Command executed successfully. Output:\n%s\n", result)
}

