package main

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Strict input validation for loadBalancerName
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}

	// Validate loadBalancerName contains only safe characters
	// Allow alphanumeric, hyphens, underscores, and dots
	if !isValidName(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName: contains unsafe characters")
	}

	// Validate and sanitize outputFile path
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Clean the path and prevent directory traversal
	cleanPath := filepath.Clean(outputFile)

	// Ensure the path doesn't contain dangerous patterns
	if strings.Contains(cleanPath, "..") {
		return "", fmt.Errorf("invalid outputFile: path traversal detected")
	}

	// Ensure it has .json extension for safety
	if !strings.HasSuffix(cleanPath, ".json") {
		return "", fmt.Errorf("invalid outputFile: must have .json extension")
	}

	// Execute commands separately without shell to prevent injection
	// Step 1: Run aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", 
		"--LoadBalancerName", loadBalancerName)

	aliyunOutput, err := aliyunCmd.Output()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, string(exitErr.Stderr))
		}
		return "", fmt.Errorf("aliyun command failed: %w", err)
	}

	// Step 2: Run jq command with the output from aliyun
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = strings.NewReader(string(aliyunOutput))

	jqOutput, err := jqCmd.Output()
	if err != nil {
		if exitErr, ok := err.(*exec.ExitError); ok {
			return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, string(exitErr.Stderr))
		}
		return "", fmt.Errorf("jq command failed: %w", err)
	}

	// Step 3: Write output to file
	err = os.WriteFile(cleanPath, jqOutput, 0644)
	if err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return string(jqOutput), nil
}

// isValidName checks if the name contains only safe characters
func isValidName(name string) bool {
	if name == "" {
		return false
	}

	for _, ch := range name {
		if !((ch >= 'a' && ch <= 'z') ||
			(ch >= 'A' && ch <= 'Z') ||
			(ch >= '0' && ch <= '9') ||
			ch == '-' || ch == '_' || ch == '.') {
			return false
		}
	}

	return true
}

