// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate loadBalancerName - allow only alphanumeric, hyphens, underscores, and dots
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}
	if !isValidLoadBalancerName(loadBalancerName) {
		return "", fmt.Errorf("invalid loadBalancerName: contains disallowed characters")
	}

	// Validate and sanitize outputFile path
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Clean the path and check for path traversal attempts
	cleanPath := filepath.Clean(outputFile)
	if strings.Contains(cleanPath, "..") {
		return "", fmt.Errorf("invalid outputFile: path traversal detected")
	}

	// Ensure the output file has .json extension for safety
	if !strings.HasSuffix(cleanPath, ".json") {
		return "", fmt.Errorf("invalid outputFile: must have .json extension")
	}

	// Execute aliyun command with proper argument passing (no shell)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", 
		"--LoadBalancerName", loadBalancerName)

	// Execute jq command with proper argument passing (no shell)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create output file
	outFile, err := os.Create(cleanPath)
	if err != nil {
		return "", fmt.Errorf("failed to create output file: %w", err)
	}
	defer outFile.Close()

	// Set up the pipeline: aliyun | jq > file
	jqCmd.Stdin, err = aliyunCmd.StdoutPipe()
	if err != nil {
		return "", fmt.Errorf("failed to create pipe: %w", err)
	}

	jqCmd.Stdout = outFile

	// Capture stderr for both commands
	var aliyunStderr, jqStderr strings.Builder
	aliyunCmd.Stderr = &aliyunStderr
	jqCmd.Stderr = &jqStderr

	// Start jq first (it will wait for input)
	if err := jqCmd.Start(); err != nil {
		return "", fmt.Errorf("failed to start jq command: %w", err)
	}

	// Start aliyun command
	if err := aliyunCmd.Run(); err != nil {
		jqCmd.Process.Kill()
		jqCmd.Wait()
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Wait for jq to finish
	if err := jqCmd.Wait(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	successMsg := fmt.Sprintf("Successfully exported SLB data to %s", cleanPath)
	return successMsg, nil
}

// isValidLoadBalancerName checks if the load balancer name contains only safe characters
func isValidLoadBalancerName(name string) bool {
	// Allow alphanumeric characters, hyphens, underscores, and dots
	// This is a whitelist approach which is more secure
	for _, char := range name {
