// QuerySLBAndExport executes the aliyun CLI command to describe SLB,
// processes the output with jq, and saves it to the specified file.
// Returns the stdout of the command pipeline and any error encountered.
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Validate loadBalancerName
	if loadBalancerName == "" {
		return "", fmt.Errorf("loadBalancerName cannot be empty")
	}

	// Validate outputFile
	if outputFile == "" {
		return "", fmt.Errorf("outputFile cannot be empty")
	}

	// Additional validation: prevent path traversal and ensure safe file path
	cleanPath := filepath.Clean(outputFile)
	if strings.Contains(cleanPath, "..") {
		return "", fmt.Errorf("invalid output file path: path traversal detected")
	}

	// Validate that the file has a reasonable extension
	if !strings.HasSuffix(cleanPath, ".json") {
		return "", fmt.Errorf("output file must have .json extension")
	}

	// Execute aliyun command with proper argument passing (no shell)
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	var aliyunOutput bytes.Buffer
	var aliyunStderr bytes.Buffer
	aliyunCmd.Stdout = &aliyunOutput
	aliyunCmd.Stderr = &aliyunStderr

	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("aliyun command failed: %w, stderr: %s", err, aliyunStderr.String())
	}

	// Execute jq command with proper argument passing (no shell)
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")
	jqCmd.Stdin = &aliyunOutput

	var jqOutput bytes.Buffer
	var jqStderr bytes.Buffer
	jqCmd.Stdout = &jqOutput
	jqCmd.Stderr = &jqStderr

	if err := jqCmd.Run(); err != nil {
		return "", fmt.Errorf("jq command failed: %w, stderr: %s", err, jqStderr.String())
	}

	// Write output to file with proper permissions
	outputData := jqOutput.Bytes()
	if err := os.WriteFile(cleanPath, outputData, 0644); err != nil {
		return "", fmt.Errorf("failed to write output file: %w", err)
	}

	return jqOutput.String(), nil
}

