// QuerySLBAndExport queries SLB information using aliyun CLI and exports it to a file
// It executes: aliyun slb DescribeLoadBalancers --LoadBalancerName NAME | jq '.LoadBalancers.LoadBalancer[]' > output.json
func QuerySLBAndExport(loadBalancerName string, outputFile string) (string, error) {
	// Create the aliyun command
	aliyunCmd := exec.Command("aliyun", "slb", "DescribeLoadBalancers", "--LoadBalancerName", loadBalancerName)

	// Create the jq command
	jqCmd := exec.Command("jq", ".LoadBalancers.LoadBalancer[]")

	// Create a buffer to capture the output from aliyun command
	var aliyunOutput bytes.Buffer
	var aliyunError bytes.Buffer
	aliyunCmd.Stdout = &aliyunOutput
	aliyunCmd.Stderr = &aliyunError

	// Execute aliyun command
	if err := aliyunCmd.Run(); err != nil {
		return "", fmt.Errorf("failed to execute aliyun command: %v, stderr: %s", err, aliyunError.String())
	}

	// Set the output of aliyun command as input to jq command
	jqCmd.Stdin = &aliyunOutput

	// Create a buffer to capture the output from jq command
	var jqOutput bytes.Buffer
	var jqError bytes.Buffer
	jqCmd.Stdout = &jqOutput
